smartPlanningProposalList?.addEventListener("click", (event) => {
  const weekSelectButton = event.target.closest("[data-smart-planning-week-select]");

  if (weekSelectButton) {
    const targetWeek = weekSelectButton.dataset.smartPlanningWeekSelect || "";
    if (!smartPlanningProposalState?.weeks?.length) {
      activeSmartPlanningTab = "proposal";
      setSmartPlanningFocusedWeek(targetWeek);
      pendingSmartPlanningScrollWeek = targetWeek;
      createSmartPlanningAdjustmentProposal({ render: false, silent: true });
      focusSmartPlanningWeek(targetWeek);
      return;
    }

    focusSmartPlanningWeek(targetWeek);
    return;
  }

  const inlineMakeProposalButton = event.target.closest("[data-smart-planning-make-proposal-inline]");

  if (inlineMakeProposalButton) {
    const targetWeek = inlineMakeProposalButton.closest("[data-smart-planning-week-key]")?.dataset.smartPlanningWeekKey || smartPlanningFocusedWeek;
    autoFillSmartPlanningProposal({ weekValue: targetWeek });
    return;
  }

  const restoreWeekButton = event.target.closest("[data-smart-planning-restore-week]");

  if (restoreWeekButton) {
    if (!restoreSmartPlanningProposalWeek(restoreWeekButton.dataset.smartPlanningRestoreWeek || "")) {
      showMessage("Er is geen vorig voorstel om te herstellen.", "warning");
    }
    return;
  }

  const clearWeekCancelButton = event.target.closest("[data-smart-planning-clear-week-cancel]");

  if (clearWeekCancelButton) {
    smartPlanningClearWeekConfirmVisible = false;
    renderSmartPlanningPanel();
    return;
  }

  const clearWeekConfirmButton = event.target.closest("[data-smart-planning-clear-week-confirm]");

  if (clearWeekConfirmButton) {
    if (!clearSmartPlanningProposalWeek()) {
      showMessage("Er is nog geen weekvoorstel om te wissen.", "warning");
    }
    return;
  }

  const applyCancelButton = event.target.closest("[data-smart-planning-apply-cancel]");

  if (applyCancelButton) {
    if (smartPlanningIsSavingRoster) {
      return;
    }
    smartPlanningApplyConfirmVisible = false;
    renderSmartPlanningPanel();
    return;
  }

  const applyConfirmButton = event.target.closest("[data-smart-planning-apply-confirm]");

  if (applyConfirmButton) {
    startSmartPlanningRosterSave();
    return;
  }

  const clearChoiceButton = event.target.closest("[data-smart-planning-clear-choice]");

  if (clearChoiceButton) {
    clearSmartPlanningProposalAssignment(clearChoiceButton.dataset.smartPlanningClearChoice || "");
    return;
  }

  const keepOpenButton = event.target.closest("[data-smart-planning-keep-open]");

  if (keepOpenButton) {
    event.stopPropagation();
    setSmartPlanningProposalKeepOpen(
      keepOpenButton.dataset.smartPlanningKeepOpen || "",
      keepOpenButton.dataset.keepOpen !== "false"
    );
    return;
  }

  const employeeChoiceButton = event.target.closest("[data-smart-planning-employee-choice]");

  if (employeeChoiceButton) {
    const isAvailable = employeeChoiceButton.dataset.employeeAvailable === "true";
    const employeeName = employeeChoiceButton.dataset.employeeName || "";
    const itemId = employeeChoiceButton.dataset.smartPlanningEmployeeChoice || "";

    if (!isAvailable) {
      showMessage(`${employeeName} is niet beschikbaar: ${employeeChoiceButton.dataset.employeeReason || "controle nodig"}.`, "warning");
      return;
    }

    selectSmartPlanningProposalEmployee(itemId, employeeName, { assignSeries: event.shiftKey });
    return;
  }

  const button = event.target.closest("[data-smart-planning-open-shift]");

  if (!button) {
    return;
  }

  selectedSmartPlanningOpenShiftId = button.dataset.smartPlanningOpenShift || "";
  setSmartPlanningFocusedWeek(getSmartPlanningWeekValueForItemId(selectedSmartPlanningOpenShiftId));
  renderSmartPlanningPanel();
});

